def test_error_handling_invalid_syntax() -> None:
    """Parsing invalid syntax should produce a tree with error nodes."""
    source = "function function function @@@ %%%"
    config = {"language": "javascript"}

    _ = process(source, config)


def test_error_handling_unknown_language() -> None:
    """Loading a nonexistent language should produce an error."""
    with pytest.raises(Exception):  # noqa: B017
        source = ""
        config = {"language": "nonexistent_xyz"}
        process(source, config)


def test_error_process_empty_source() -> None:
    """Process empty source code succeeds with zero metrics."""
    source = ""
    config = {"language": "python"}

    result = process(source, config)
    assert result.metrics.total_lines == 0  # noqa: S101


def test_parse_empty_language() -> None:
    """process() returns error with empty language name."""
    with pytest.raises(Exception):  # noqa: B017
        source = "x = 1"
        config = {"language": ""}
        process(source, config)


def test_process_unknown_language() -> None:
    """process() returns error when config language is unknown."""
    with pytest.raises(Exception):  # noqa: B017
        source = "x = 1"
        config = {"language": "nonexistent_xyz"}
        process(source, config)
